for i, encoded_file in enumerate(encoded_files):
    decoded_file = base64.b64decode(encoded_file).decode('utf-8')
    image_url = decoded_file
    image_response = requests.get(image_url)

    if image_response.status_code == 200:
        file_path = os.path.join(save_dir, f"Passau_rk-Bistum_Kirn_Register_Sterbefälle_007_{i + 1}.jpg")
        with open(file_path, "wb") as file:
            file.write(image_response.content)
        print(f"Downloaded {file_path}")
    else:
        print(f"Failed to download {file_path}")

print("Download completed.")
